                  "elements":[ "K", "S", "W" ],
                  "nelements":3,
                  "elements_ratios":[
                     0.007425742574257425,
                     0.0024752475247524753,
                     0.9900990099009901
                  ]
               }
            }
         }
      }
   }
}
```

Note that glob patterns are expected. Thus, if  the `include` field is set to `*elements`, it will include all keys that end with `elements`.

```json hl_lines="9"
{
   "entries":{
      "x36WdKPMctUOkjXMyV8oQq2zWcSx":{
